// Test cases to validate the fix for extension property naming issue
// These tests ensure that extension properties with custom getters are NOT flagged
// for screaming snake case, regardless of whether they have annotations or modifiers

// Mock classes and annotations for testing
class Context {
    companion object {
        const val SYSTEM_SERVICE_AD_DELEGATE_FACTORY = "service"
    }
}

class AdsDelegateFactory

@Suppress("PropertyName")
annotation class SuppressLint(val value: String)

// Test Case 1: Extension property WITH annotation before getter
// Should NOT be flagged because it has a custom getter
val Context.adsDelegateFactory @SuppressLint("WrongConstant") get() =
    (null as Any) as AdsDelegateFactory

// Test Case 2: Extension property with PRIVATE modifier before getter
// Should NOT be flagged because it has a custom getter
val Context.adsDelegateFactory2 private get() =
    (null as Any) as AdsDelegateFactory

// Test Case 3: Extension property WITHOUT annotation or modifier
// Should NOT be flagged because it has a custom getter
val Context.adsDelegateFactory3 get() =
    (null as Any) as AdsDelegateFactory

// Test Case 4: Extension property with PUBLIC modifier before getter
// Should NOT be flagged because it has a custom getter
val Context.adsDelegateFactory4 public get() =
    (null as Any) as AdsDelegateFactory

// Test Case 5: Extension property with multiple modifiers before getter
// Should NOT be flagged because it has a custom getter
val Context.adsDelegateFactory5 @SuppressLint("WrongConstant") private get() =
    (null as Any) as AdsDelegateFactory

// Test Case 6: Regular property (non-extension) with custom getter and annotation
// Should NOT be flagged because it has a custom getter
val regularProperty @SuppressLint("WrongConstant") get() = 42

// Test Case 7: Regular property (non-extension) with custom getter and private modifier
// Should NOT be flagged because it has a custom getter
val regularProperty2 private get() = 43

// Test Case 8: Top-level property WITHOUT custom getter
// Should be flagged with screaming snake case violation
val wrongName = 44

// Test Case 9: Object property WITHOUT custom getter
// Should be flagged with screaming snake case violation
object TestObject {
    val wrongName = 45
}

// Test Case 10: Top-level const property without custom getter
// Should be flagged with screaming snake case violation
const val wrongConstName = 46"}

