    private val propertyNamingRuleAssertThat =
        KtLintAssertThat.assertThatRule { PropertyNamingRule() }

    @Test
    fun `Given an extension property with annotation and custom getter then do not emit`() {
        val code =
            """
            class Context { companion object { const val SERVICE = "test" } }
            @Suppress("PropertyName")
            annotation class SuppressLint(val value: String)

            val Context.adsDelegateFactory @SuppressLint("WrongConstant") get() =
                (null as Any) as Any
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an extension property with private modifier and custom getter then do not emit`() {
        val code =
            """
            class Context { companion object { const val SERVICE = "test" } }

            val Context.adsDelegateFactory private get() = (null as Any) as Any
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an extension property with public modifier and custom getter then do not emit`() {
        val code =
            """
            class Context { companion object { const val SERVICE = "test" } }

            val Context.adsDelegateFactory public get() = (null as Any) as Any
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an extension property without annotation or modifier and with custom getter then do not emit`() {
        val code =
            """
