            val Context.adsDelegateFactory get() = (null as Any) as Any
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an extension property with annotation and private modifier and custom getter then do not emit`() {
        val code =
            """
            class Context { companion object { const val SERVICE = "test" } }
            @Suppress("PropertyName")
            annotation class SuppressLint(val value: String)

            val Context.adsDelegateFactory @SuppressLint("WrongConstant") private get() = (null as Any) as Any
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a regular property with annotation and custom getter then do not emit`() {
        val code =
            """
            @Suppress("PropertyName")
            annotation class SuppressLint(val value: String)

            val regularProperty @SuppressLint("WrongConstant") get() = 42
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a regular property with private modifier and custom getter then do not emit`() {
        val code =
            """
            val regularProperty private get() = 42
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a regular property with annotation and private modifier and custom getter then do not emit`() {
        val code =
            """
            @Suppress("PropertyName")
            annotation class SuppressLint(val value: String)

            val regularProperty @SuppressLint("WrongConstant") private get() = 42
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }
}"}

